import pandas as pd
import json
import ast

# Load previous tool results
reviews = var_call_iE0WiM7tLToUOYOrbHK7cN19
books_path = var_call_KtTj1UioDooPmQdRuTfPjJvU

# Read books JSON
with open(books_path, 'r', encoding='utf-8') as f:
    books = json.load(f)

# DataFrames
df_rev = pd.DataFrame(reviews)
df_books = pd.DataFrame(books)

# Ensure columns exist
for col in ['purchase_id', 'avg_rating', 'review_count']:
    if col not in df_rev.columns:
        df_rev[col] = None

# Convert types safely
df_rev['avg_rating'] = pd.to_numeric(df_rev['avg_rating'], errors='coerce')
df_rev['review_count'] = pd.to_numeric(df_rev['review_count'], errors='coerce').fillna(0).astype(int)

# Map purchase_id to book_id
if 'purchase_id' in df_rev.columns:
    df_rev['book_id'] = df_rev['purchase_id'].astype(str).str.replace('purchaseid_', 'bookid_', regex=False)
else:
    df_rev['book_id'] = None

# Parse categories into lists

def parse_categories(s):
    if s is None:
        return []
    if isinstance(s, list):
        return s
    try:
        # Some entries are strings representing lists
        parsed = ast.literal_eval(s)
        if isinstance(parsed, list):
            return parsed
        else:
            return []
    except Exception:
        # fallback: look for the substring
        if isinstance(s, str) and "Children" in s:
            return [s]
        return []

if 'categories' in df_books.columns:
    df_books['categories_list'] = df_books['categories'].apply(parse_categories)
else:
    df_books['categories_list'] = [[] for _ in range(len(df_books))]

# Filter reviews with avg_rating >= 4.5
df_good = df_rev[df_rev['avg_rating'] >= 4.5].copy()

# Merge
df_merged = pd.merge(df_good, df_books, on='book_id', how='left', suffixes=('_rev','_book'))

# Determine if category includes "Children's Books"
def includes_childrens(x):
    try:
        return isinstance(x, list) and ("Children's Books" in x)
    except Exception:
        return False

if 'categories_list' in df_merged.columns:
    df_merged['is_children'] = df_merged['categories_list'].apply(includes_childrens)
else:
    df_merged['is_children'] = False

# Final filtered rows
df_final = df_merged[df_merged['is_children']].copy()

# Build output
output = []
for _, r in df_final.iterrows():
    output.append({
        'book_id': r.get('book_id') if pd.notna(r.get('book_id')) else None,
        'title': r.get('title') if pd.notna(r.get('title')) else None,
        'avg_rating': float(r.get('avg_rating')) if pd.notna(r.get('avg_rating')) else None,
        'review_count': int(r.get('review_count')) if pd.notna(r.get('review_count')) else None,
        'categories': r.get('categories_list') if pd.notna(r.get('categories_list')) else []
    })

print("__RESULT__:")
print(json.dumps(output))

